{"content":"body {
  font-family: Arial, sans-serif;
  background: #f4f6fb;
  margin: 0;
  padding: 0;
}

.quiz-container {
  max-width: 500px;
  margin: 40px auto;
  background: #fff;
  border-radius: 12px;
  box-shadow: 0 2px 16px rgba(0,0,0,0.08);
  padding: 32px 24px;
}

h1 {
  text-align: center;
  color: #2d3a4b;
}

.question-section h2 {
  margin-bottom: 8px;
  color: #3b4a5a;
}

.options {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin: 20px 0;
}

.options button {
  padding: 10px 16px;
  border: 1px solid #bfc9d9;
  border-radius: 6px;
  background: #f7f9fc;
  cursor: pointer;
  font-size: 16px;
  transition: background 0.2s, border 0.2s;
}

.options button.selected {
  background: #d0e6ff;
  border-color: #409eff;
}

.options button:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

.next-btn {
  width: 100%;
  padding: 12px;
  background: #409eff;
  color: #fff;
  border: none;
  border-radius: 6px;
  font-size: 18px;
  cursor: pointer;
  margin-top: 10px;
  transition: background 0.2s;
}

.next-btn:disabled {
  background: #bfc9d9;
  cursor: not-allowed;
}

.score-section {
  text-align: center;
}

.score-section h2 {
  color: #409eff;
}

.score-section button {
  margin-top: 20px;
  padding: 10px 20px;
  background: #2d3a4b;
  color: #fff;
  border: none;
  border-radius: 6px;
  font-size: 16px;
  cursor: pointer;
}
